function Set-Status {
    param($text, $type = "info")
    $clr = switch ($type) { "ok" { $clrGreen }"warn" { $clrAmber }"error" { $clrRed }default { $clrTextDim } }
    $statusLabel.ForeColor = $clr
    $statusLabel.Text = "  $text"
}

function Write-Log {
    param($message, $type = "info")
    $clr = switch ($type) {
        "ok" { $clrGreen }"warn" { $clrAmber }"error" { $clrRed }
        "title" { $clrAccent }"sep" { $clrBorder }default { $clrText }
    }
    if ($null -eq $script:activeLogBox) { return }
    $box = $script:activeLogBox
    $ts = (Get-Date).ToString("HH:mm:ss")
    $act = [Action] {
        $box.SelectionStart = $box.TextLength
        $box.SelectionLength = 0
        $box.SelectionColor = $clr
        $box.AppendText("[$ts]  $message`n")
        $box.ScrollToCaret()
    }
    if ($box.InvokeRequired) { $box.Invoke($act) } else { $act.Invoke() }
}

function Write-Sep { Write-Log "--------------------------------------" "sep" }

function New-StyledButton {
    param([string]$text, [int]$x, [int]$y, [int]$w = 270, [int]$h = 38,
        [System.Windows.Forms.Control]$parent, [System.Drawing.Color]$borderColor)
    if (-not $borderColor) { $borderColor = $clrAccent }
    $btn = New-Object System.Windows.Forms.Button
    $btn.Text = $text; $btn.Size = New-Object System.Drawing.Size($w, $h)
    $btn.Location = New-Object System.Drawing.Point($x, $y); $btn.FlatStyle = "Flat"
    $btn.FlatAppearance.BorderColor = $borderColor; $btn.FlatAppearance.BorderSize = 1
    $btn.BackColor = $clrPanelAlt; $btn.ForeColor = $clrText; $btn.Font = $fntBtn
    $btn.Cursor = [System.Windows.Forms.Cursors]::Hand; $btn.Tag = $borderColor
    $btn.Add_MouseEnter({ $this.BackColor = [System.Drawing.Color]::FromArgb(20, 40, 60); $this.ForeColor = $this.Tag })
    $btn.Add_MouseLeave({ $this.BackColor = $clrPanelAlt; $this.ForeColor = $clrText })
    $parent.Controls.Add($btn); return $btn
}

