function Lock-UI {
    param([bool]$lock)
    $script:isRunning = $lock
    $en = -not $lock
    if ($lock) { $btnAuto.BackColor = [System.Drawing.Color]::FromArgb(0, 30, 40) }
    else { $btnAuto.BackColor = [System.Drawing.Color]::FromArgb(0, 50, 30) }
    if ($btnAuto.InvokeRequired) { $btnAuto.Invoke([Action] { $btnAuto.Enabled = $en }) }
    else { $btnAuto.Enabled = $en }
    if ($null -ne $script:indivButtons) {
        foreach ($b in $script:indivButtons) {
            $bRef = $b
            if ($bRef.InvokeRequired) { $bRef.Invoke([Action] { $bRef.Enabled = $en }) }
            else { $bRef.Enabled = $en }
        }
    }
}

function Reset-UI {
    param($duration = "")
    $progressBar.Style = "Continuous"
    $progressBar.Value = 0
    $progressBar.Visible = $false
    $btnStop.Visible = $false
    $btnStop.Enabled = $true
    if ($duration -ne "") { $lblStep.Text = "Sequence terminee — Duree : $duration" }
    else { $lblStep.Text = "Operation terminee." }
    Lock-UI $false
}

