function Show-Report {
    param($duration)
    $order = @("CHKDSK", "DISM ScanHealth", "DISM RestoreHealth", "SFC", "WinSxS Nettoyage")
    $lines = foreach ($step in $order) {
        if ($script:stepResults.ContainsKey($step)) {
            $r = $script:stepResults[$step]
            if ($r.Ok) {
                $icon = "[OK]"; $status = "OK"
            }
            elseif ($r.Code -eq -2146498554) {
                $icon = "[>>]"; $status = "Redemarrage requis"
            }
            else {
                $icon = "[!!]"; $status = "Erreur $($r.Code)"
            }
            "  $icon  $($step.PadRight(20)) $status"
        }
    }
    $body = $lines -join "`n"
    $act = [Action] {
        $lblReportBody.Text = $body
        $lblReportDuration.Text = "Duree totale :`n$duration"
        $pnlReport.Visible = $true
    }
    if ($pnlReport.InvokeRequired) { $pnlReport.Invoke($act) } else { $act.Invoke() }
}

