function Export-Log {
    $sfd = New-Object System.Windows.Forms.SaveFileDialog
    $sfd.Filter   = "Fichier texte (*.txt)|*.txt"
    $sfd.FileName = "winmedic_log_$(Get-Date -Format 'yyyyMMdd_HHmmss').txt"
    $sfd.Title    = "Exporter le journal - WinMedic"
    if ($sfd.ShowDialog() -eq [System.Windows.Forms.DialogResult]::OK) {
        $box     = $script:activeLogBox
        $content = if ($box.Lines.Count -gt 0) { $box.Lines -join "`r`n" } else { $box.Text }
        # UTF-8 avec BOM — assure l'affichage correct des accents dans tout editeur
        $utf8Bom = New-Object System.Text.UTF8Encoding($true)
        [System.IO.File]::WriteAllText($sfd.FileName, $content, $utf8Bom)
        Write-Log "Journal exporte : $($sfd.FileName)" "ok"
        Set-Status "Log exporte" "ok"
    }
}
$btnExportLog1.Add_Click({ $script:activeLogBox = $logBoxAuto; Export-Log })
$btnExportLog2.Add_Click({ $script:activeLogBox = $logBoxIndiv; Export-Log })

$btnBrowseISO.Add_Click({
        $fd = New-Object System.Windows.Forms.OpenFileDialog
        $fd.Filter = "Image Windows (*.iso)|*.iso"
        $fd.Title = "Selectionner une image ISO Windows"
        if ($fd.ShowDialog() -eq [System.Windows.Forms.DialogResult]::OK) {
            $txtISOPath.Text = $fd.FileName; $txtISOPath.ForeColor = $clrText
            $cbForceISO.Checked = $true
            Write-Log "ISO selectionne : $($fd.FileName)" "ok"
        }
    })

$cbForceISO.Add_CheckedChanged({
        if (-not $cbForceISO.Checked) {
            $txtISOPath.Text = "Aucun ISO selectionne..."
            $txtISOPath.ForeColor = $clrTextDim
        }
    })

$btnStop.Add_Click({
        $script:stopRequested = $true
        if (-not [string]::IsNullOrEmpty($script:stopFile)) {
            try { "" | Out-File -FilePath $script:stopFile -Encoding UTF8 -ErrorAction SilentlyContinue } catch {}
        }
        Write-Log "Arret demande par l'utilisateur." "warn"
        Set-Status "Arret en cours..." "warn"
        $btnStop.Enabled = $false
    })

# ============================================================
# BOUTON AUTO — SEQUENCE COMPLETE
# ============================================================
$btnAuto.Add_Click({
        if ($script:isRunning) { Write-Log "Operation deja en cours." "warn"; return }

        $pnlReport.Visible = $false
        $script:stepResults = @{}
        $script:stopRequested = $false
        $script:opStartTime = Get-Date

        $script:sentinelFile = $env:TEMP + "\" + [System.Guid]::NewGuid().ToString() + ".sentinel"
        $script:stopFile = $env:TEMP + "\" + [System.Guid]::NewGuid().ToString() + ".stop"

        Lock-UI $true
        $progressBar.Style = "Marquee"
        $progressBar.Visible = $true
        $btnStop.Visible = $true
        $btnStop.Enabled = $true
        $timerSpinner.Start()
        $script:activeLogBox = $logBoxAuto
        $lblStep.Text = "[ >... ] Sequence en cours..."

        Write-Log "======================================" "title"
        Write-Log "  DEMARRAGE SEQUENCE AUTOMATIQUE"       "title"
        Write-Log "======================================" "title"

        $RS_LogBox = $logBoxAuto
        $RS_CbISO = $cbForceISO
        $RS_TxtISO = $txtISOPath
        $RS_Timeout = $script:timeoutMinutes
        $RS_Sentinel = $script:sentinelFile
        $RS_StopFile = $script:stopFile
        $RS_G = $clrGreen; $RS_A = $clrAmber; $RS_R = $clrRed
        $RS_Ac = $clrAccent; $RS_T = $clrText; $RS_B = $clrBorder

        $runspace = [System.Management.Automation.Runspaces.RunspaceFactory]::CreateRunspace()
        $runspace.ApartmentState = "STA"
        $runspace.ThreadOptions = "ReuseThread"
        $runspace.Open()

        $varMap = @{
            logBoxAuto = $RS_LogBox
            cbForceISO = $RS_CbISO; txtISOPath = $RS_TxtISO
            timeoutMinutes = $RS_Timeout
            sentinelFile = $RS_Sentinel; stopFile = $RS_StopFile
            clrGreen = $RS_G; clrAmber = $RS_A; clrRed = $RS_R
            clrAccent = $RS_Ac; clrText = $RS_T; clrBorder = $RS_B
        }
        foreach ($kv in $varMap.GetEnumerator()) {
            $runspace.SessionStateProxy.SetVariable($kv.Key, $kv.Value)
        }

        $ps = [System.Management.Automation.PowerShell]::Create()
        $ps.Runspace = $runspace

        $ps.AddScript({

                $oemCP = [System.Text.Encoding]::GetEncoding(
                    [System.Globalization.CultureInfo]::CurrentCulture.TextInfo.OEMCodePage
                )

                function RS-Log {
                    param($msg, $type = "info")
                    $clr = switch ($type) {
                        "ok" { $clrGreen }
                        "warn" { $clrAmber }
                        "error" { $clrRed }
                        "title" { $clrAccent }
                        "sep" { $clrBorder }
                        default { $clrText }
                    }
                    $logBoxAuto.Invoke([Action] {
                            $logBoxAuto.SelectionStart = $logBoxAuto.TextLength
                            $logBoxAuto.SelectionLength = 0
                            $logBoxAuto.SelectionColor = $clr
                            $logBoxAuto.AppendText("[$((Get-Date).ToString('HH:mm:ss'))]  $msg`n")
                            $logBoxAuto.ScrollToCaret()
                        })
                }

                function RS-StopRequested { return (Test-Path $stopFile) }

                $results = @{}
                function RS-Record {
                    param($name, [bool]$ok, $code = 0)
                    $results[$name] = @{Ok = $ok; Code = $code }
                }

                function RS-RunCmd {
                    param($exe, $cmdArgs)
                    $script:RS_LastExit = -999
                    $pRef = $null
                    try {
                        $psi = New-Object System.Diagnostics.ProcessStartInfo
                        $psi.FileName = $exe
                        $psi.Arguments = $cmdArgs
                        $psi.RedirectStandardOutput = $true
                        $psi.RedirectStandardError = $true
                        $psi.UseShellExecute = $false
                        $psi.CreateNoWindow = $true
                        $psi.StandardOutputEncoding = $oemCP
                        $psi.StandardErrorEncoding = $oemCP
                        $proc = New-Object System.Diagnostics.Process
                        $pRef = $proc
                        $proc.StartInfo = $psi
                        $proc.Start() | Out-Null
                        $dl = (Get-Date).AddMinutes($timeoutMinutes)
                        while (-not $proc.StandardOutput.EndOfStream) {
                            if (RS-StopRequested) {
                                RS-Log "Arret demande — arret du processus." "warn"
                                try { $proc.Kill() } catch {}
                                $script:RS_LastExit = -2
                                return
                            }
                            if ((Get-Date) -gt $dl) {
                                RS-Log "TIMEOUT ($timeoutMinutes min)." "error"
                                try { $proc.Kill() } catch {}
                                $script:RS_LastExit = -1
                                return
                            }
                            $raw = $proc.StandardOutput.ReadLine()
                            if (-not [string]::IsNullOrWhiteSpace($raw)) { RS-Log $raw.Trim() }
                        }
                        $proc.WaitForExit(60000) | Out-Null
                        $errRaw = $proc.StandardError.ReadToEnd()
                        if (-not [string]::IsNullOrWhiteSpace($errRaw)) {
                            foreach ($el in ($errRaw -split "`r`n|`n")) {
                                if (-not [string]::IsNullOrWhiteSpace($el)) { RS-Log $el.Trim() "warn" }
                            }
                        }
                        $script:RS_LastExit = [int]$proc.ExitCode
                    }
                    catch {
                        RS-Log "ERREUR RS-RunCmd : $($_.Exception.Message)" "error"
                        $script:RS_LastExit = -999
                    }
                    finally {
                        if ($null -ne $pRef) {
                            try { if (-not $pRef.HasExited) { $pRef.Kill() } } catch {}
                        }
                    }
                }

                $REBOOT_CODE = -2146498554

                try {
                    if (RS-StopRequested) { return }
                    RS-Log ""; RS-Log "[ ETAPE 0 ] Verification C:\Windows\System32" "title"
                    if (-not (Test-Path "C:\Windows\System32")) {
                        RS-Log "ERREUR : C:\Windows\System32 introuvable. Abandon." "error"; return
                    }
                    RS-Log "OK  C:\Windows\System32 trouve." "ok"

                    if (RS-StopRequested) { return }
                    RS-Log ""; RS-Log "[ ETAPE 1 ] CHKDSK — Diagnostic C: (lecture seule)" "title"
                    try {
                        $chkOut = & chkdsk C: 2>&1 | Out-String
                        foreach ($line in ($chkOut -split "`n")) {
                            if (-not [string]::IsNullOrWhiteSpace($line)) { RS-Log $line.Trim() }
                        }
                        RS-Record "CHKDSK" $true 0
                        RS-Log "OK  CHKDSK termine." "ok"
                    }
                    catch {
                        RS-Log "ERREUR CHKDSK : $($_.Exception.Message)" "error"
                        RS-Record "CHKDSK" $false -1
                    }

                    if (RS-StopRequested) { return }
                    RS-Log ""; RS-Log "[ ETAPE 2 ] DISM — ScanHealth" "title"
                    RS-Log "Cette etape peut prendre plusieurs minutes..." "warn"

                    $isoForce = $cbForceISO.Invoke([Func[object]] { $cbForceISO.Checked })
                    $isoPath2 = $txtISOPath.Invoke([Func[object]] { $txtISOPath.Text })

                    if ($isoForce -and $isoPath2 -ne "Aucun ISO selectionne..." -and $isoPath2 -ne "") {
                        RS-Log "Mode ISO force." "warn"
                        try {
                            if (Test-Path $isoPath2) {
                                $diskImg = Mount-DiskImage -ImagePath $isoPath2 -PassThru -ErrorAction Stop
                                $letter = ($diskImg | Get-Volume).DriveLetter
                                $wim = "${letter}:\sources\install.wim"
                                if (Test-Path $wim) {
                                    RS-RunCmd "DISM.exe" "/Online /Cleanup-Image /RestoreHealth /Source:wim:`"$wim`":1 /LimitAccess"
                                    $xISO = $script:RS_LastExit
                                    RS-Record "DISM ScanHealth"    $true 0
                                    RS-Record "DISM RestoreHealth" ($xISO -eq 0) $xISO
                                    if ($xISO -eq 0) { RS-Log "OK  DISM via ISO reussi." "ok" }
                                    else { RS-Log "ERREUR DISM ISO code $xISO." "error" }
                                }
                                else {
                                    RS-Log "ERREUR : install.wim introuvable." "error"
                                    RS-Record "DISM ScanHealth" $false -1; RS-Record "DISM RestoreHealth" $false -1
                                }
                            }
                        }
                        finally {
                            try { Dismount-DiskImage -ImagePath $isoPath2 -ErrorAction SilentlyContinue | Out-Null } catch {}
                        }
                    }
                    else {
                        RS-RunCmd "DISM.exe" "/Online /Cleanup-Image /ScanHealth"
                        $scanX = $script:RS_LastExit
                        RS-Record "DISM ScanHealth" ($scanX -eq 0) $scanX
                        if ($scanX -eq 0) {
                            RS-Log "OK  ScanHealth : aucun probleme." "ok"
                            if (-not (RS-StopRequested)) {
                                RS-Log ""; RS-Log "[ ETAPE 2.1 ] DISM — RestoreHealth" "title"
                                RS-RunCmd "DISM.exe" "/Online /Cleanup-Image /RestoreHealth"
                                $restX = $script:RS_LastExit
                                RS-Record "DISM RestoreHealth" ($restX -eq 0) $restX
                                if ($restX -eq 0) { RS-Log "OK  RestoreHealth termine." "ok" }
                                elseif ($restX -eq $REBOOT_CODE) { RS-Log "WARN  RestoreHealth : redemarrage requis." "warn" }
                                else { RS-Log "ERREUR RestoreHealth code $restX." "error" }
                            }
                        }
                        else {
                            RS-Log "ERREUR ScanHealth code $scanX." "error"
                            RS-Record "DISM RestoreHealth" $false $scanX
                        }
                    }

                    if (RS-StopRequested) { return }
                    RS-Log ""; RS-Log "[ ETAPE 3 ] SFC — Verification fichiers systeme" "title"
                    RS-RunCmd "sfc.exe" "/scannow"
                    $sfcX = $script:RS_LastExit
                    RS-Record "SFC" ($sfcX -eq 0) $sfcX
                    if ($sfcX -eq 0) { RS-Log "OK  SFC termine." "ok" }
                    else { RS-Log "ERREUR SFC code $sfcX." "error" }

                    if (RS-StopRequested) { return }
                    RS-Log ""; RS-Log "[ ETAPE 4 ] DISM — Nettoyage WinSxS" "title"
                    RS-Log "Operation longue — veuillez patienter..." "warn"
                    RS-RunCmd "DISM.exe" "/Online /Cleanup-Image /StartComponentCleanup"
                    $wxX = $script:RS_LastExit
                    RS-Record "WinSxS Nettoyage" ($wxX -eq 0 -or $wxX -eq $REBOOT_CODE) $wxX
                    if ($wxX -eq 0) { RS-Log "OK  WinSxS termine." "ok" }
                    elseif ($wxX -eq $REBOOT_CODE) { RS-Log "WARN  WinSxS : redemarrage requis avant nettoyage." "warn" }
                    else { RS-Log "ERREUR WinSxS code $wxX." "error" }

                    RS-Log ""; RS-Log "======================================" "title"
                    RS-Log "  SEQUENCE TERMINEE" "title"
                    RS-Log "  Redemarrage recommande." "title"
                    RS-Log "======================================" "title"

                }
                finally {
                    try {
                        $lines = @()
                        foreach ($kv in $results.GetEnumerator()) { $lines += "$($kv.Key)|$($kv.Value.Ok)|$($kv.Value.Code)" }
                        $lines | Out-File -FilePath $sentinelFile -Encoding UTF8 -ErrorAction Stop
                    }
                    catch {
                        try { "" | Out-File -FilePath $sentinelFile -Encoding UTF8 } catch {}
                    }
                }

            }) | Out-Null

        $ps.BeginInvoke() | Out-Null

        $script:tw_Sentinel = $script:sentinelFile
        $script:tw_StartTime = $script:opStartTime
        $script:tw_PS = $ps
        $script:tw_RS = $runspace

        $timerWatch = New-Object System.Windows.Forms.Timer
        $timerWatch.Interval = 800
        $timerWatch.Add_Tick({
                param($sender, $e)
                if ([string]::IsNullOrEmpty($script:tw_Sentinel)) { return }
                if (-not (Test-Path $script:tw_Sentinel)) { return }

                $sender.Stop(); $sender.Dispose()
                $timerSpinner.Stop()

                try { $script:tw_PS.Stop() } catch {}
                try { $script:tw_PS.Dispose() } catch {}
                try { $script:tw_RS.Close() } catch {}
                try { $script:tw_RS.Dispose() } catch {}

                try {
                    $lines = Get-Content $script:tw_Sentinel -Encoding UTF8 -ErrorAction SilentlyContinue
                    foreach ($line in $lines) {
                        $parts = $line -split "\|"
                        if ($parts.Count -eq 3) {
                            $script:stepResults[$parts[0]] = @{ Ok = ($parts[1] -eq "True"); Code = [int]$parts[2] }
                        }
                    }
                    Remove-Item $script:tw_Sentinel -Force -ErrorAction SilentlyContinue
                }
                catch {}

                try { Remove-Item $script:stopFile -Force -ErrorAction SilentlyContinue } catch {}

                $elapsed = (Get-Date) - $script:tw_StartTime
                $duration = "{0}m {1}s" -f [int]$elapsed.TotalMinutes, $elapsed.Seconds

                Show-Report $duration
                Reset-UI $duration
                Set-Status "Sequence terminee — Redemarrage recommande" "ok"

                if (-not $script:stopRequested) {
                    [System.Windows.Forms.MessageBox]::Show(
                        "Sequence de reparation terminee.`nDuree : $duration`n`nUn redemarrage est recommande.",
                        "Termine — WinMedic  © ofbridge_lab",
                        [System.Windows.Forms.MessageBoxButtons]::OK,
                        [System.Windows.Forms.MessageBoxIcon]::Information)
                }
            })
        $timerWatch.Start()
    })

# ============================================================
# RUN-INDIVOP
# ============================================================
function Run-IndivOp {
    param($title, [scriptblock]$userBlock)
    if ($script:isRunning) { Write-Log "Operation deja en cours." "warn"; return }

    $script:activeLogBox = $logBoxIndiv
    Lock-UI $true
    $timerSpinner.Start()
    Write-Sep
    Write-Log "-- $title" "title"

    $indivSentinel = $env:TEMP + "\" + [System.Guid]::NewGuid().ToString() + ".sentinel"
    $blockCode = $userBlock.ToString()

    $IV_LogBox = $logBoxIndiv
    $IV_Timeout = $script:timeoutMinutes
    $IV_Sentinel = $indivSentinel
    $IV_G = $clrGreen; $IV_A = $clrAmber; $IV_R = $clrRed
    $IV_Ac = $clrAccent; $IV_T = $clrText; $IV_B = $clrBorder

    $runspace2 = [System.Management.Automation.Runspaces.RunspaceFactory]::CreateRunspace()
    $runspace2.ApartmentState = "STA"; $runspace2.ThreadOptions = "ReuseThread"
    $runspace2.Open()

    $varMap2 = @{
        logBoxIndiv = $IV_LogBox; timeoutMinutes = $IV_Timeout
        sentinelFile = $IV_Sentinel
        clrGreen = $IV_G; clrAmber = $IV_A; clrRed = $IV_R
        clrAccent = $IV_Ac; clrText = $IV_T; clrBorder = $IV_B
    }
    foreach ($kv in $varMap2.GetEnumerator()) {
        $runspace2.SessionStateProxy.SetVariable($kv.Key, $kv.Value)
    }

    $ps2 = [System.Management.Automation.PowerShell]::Create()
    $ps2.Runspace = $runspace2

    $fullScript = @"
`$oemCP = [System.Text.Encoding]::GetEncoding(
    [System.Globalization.CultureInfo]::CurrentCulture.TextInfo.OEMCodePage
)

function IRS-Log { param(`$msg, `$type="info")
    `$clr = switch(`$type){
        "ok"    { `$clrGreen  }
        "warn"  { `$clrAmber  }
        "error" { `$clrRed    }
        "title" { `$clrAccent }
        "sep"   { `$clrBorder }
        default { `$clrText   }
    }
    `$logBoxIndiv.Invoke([Action]{
        `$logBoxIndiv.SelectionStart  = `$logBoxIndiv.TextLength
        `$logBoxIndiv.SelectionLength = 0
        `$logBoxIndiv.SelectionColor  = `$clr
        `$logBoxIndiv.AppendText("[`$((Get-Date).ToString('HH:mm:ss'))]  `$msg``n")
        `$logBoxIndiv.ScrollToCaret()
    })
}

function IRS-RunCmd { param(`$exe, `$cmdArgs)
    `$script:IRS_LastExit = -999
    `$pRef = `$null
    try {
        `$psi = New-Object System.Diagnostics.ProcessStartInfo
        `$psi.FileName               = `$exe
        `$psi.Arguments              = `$cmdArgs
        `$psi.RedirectStandardOutput = `$true
        `$psi.RedirectStandardError  = `$true
        `$psi.UseShellExecute        = `$false
        `$psi.CreateNoWindow         = `$true
        `$psi.StandardOutputEncoding = `$oemCP
        `$psi.StandardErrorEncoding  = `$oemCP
        `$proc = New-Object System.Diagnostics.Process
        `$pRef = `$proc
        `$proc.StartInfo = `$psi
        `$proc.Start() | Out-Null
        `$dl = (Get-Date).AddMinutes(`$timeoutMinutes)
        while (-not `$proc.StandardOutput.EndOfStream) {
            if ((Get-Date) -gt `$dl) {
                IRS-Log "TIMEOUT (`$timeoutMinutes min)." "error"
                try { `$proc.Kill() } catch {}
                `$script:IRS_LastExit = -1
                return
            }
            `$raw = `$proc.StandardOutput.ReadLine()
            if (-not [string]::IsNullOrWhiteSpace(`$raw)) { IRS-Log `$raw.Trim() }
        }
        `$proc.WaitForExit(60000) | Out-Null
        `$errRaw = `$proc.StandardError.ReadToEnd()
        if (-not [string]::IsNullOrWhiteSpace(`$errRaw)) {
            foreach (`$el in (`$errRaw -split "``r``n|``n")) {
                if (-not [string]::IsNullOrWhiteSpace(`$el)) { IRS-Log `$el.Trim() "warn" }
            }
        }
        `$script:IRS_LastExit = [int]`$proc.ExitCode
    } catch {
        IRS-Log "ERREUR IRS-RunCmd : `$(`$_.Exception.Message)" "error"
        `$script:IRS_LastExit = -999
    } finally {
        if (`$null -ne `$pRef) {
            try { if (-not `$pRef.HasExited) { `$pRef.Kill() } } catch {}
        }
    }
}

try {
    $blockCode
} catch {
    IRS-Log "ERREUR : `$(`$_.Exception.Message)" "error"
} finally {
    try { "" | Out-File -FilePath `$sentinelFile -Encoding UTF8 } catch {}
}
"@

    $ps2.AddScript($fullScript) | Out-Null
    $ps2.BeginInvoke() | Out-Null

    $script:tw2_Sentinel = $indivSentinel
    $script:tw2_PS = $ps2
    $script:tw2_RS = $runspace2

    $timerW2 = New-Object System.Windows.Forms.Timer
    $timerW2.Interval = 600
    $timerW2.Add_Tick({
            param($sender, $e)
            if ([string]::IsNullOrEmpty($script:tw2_Sentinel)) { return }
            if (-not (Test-Path $script:tw2_Sentinel)) { return }

            $sender.Stop(); $sender.Dispose()
            $timerSpinner.Stop()

            try { $script:tw2_PS.Stop() } catch {}
            try { $script:tw2_PS.Dispose() } catch {}
            try { $script:tw2_RS.Close() } catch {}
            try { $script:tw2_RS.Dispose() } catch {}
            Remove-Item $script:tw2_Sentinel -Force -ErrorAction SilentlyContinue

            $lblStep.Text = "Operation terminee."
            Lock-UI $false
            Set-Status "Operation terminee" "ok"
        })
    $timerW2.Start()
}

