# ============================================================
# FORM CLOSING
# ============================================================
$form.Add_FormClosing({ param($s, $e)
        if ($script:isRunning) {
            $res = [System.Windows.Forms.MessageBox]::Show(
                "Une operation est en cours.`nForcer la fermeture ?",
                "WinMedic — Operation en cours",
                [System.Windows.Forms.MessageBoxButtons]::YesNo,
                [System.Windows.Forms.MessageBoxIcon]::Warning)
            if ($res -eq [System.Windows.Forms.DialogResult]::No) { $e.Cancel = $true; return }
            $script:stopRequested = $true
            if (-not [string]::IsNullOrEmpty($script:stopFile)) {
                try { "" | Out-File -FilePath $script:stopFile -Encoding UTF8 -ErrorAction SilentlyContinue } catch {}
            }
        }
        if ($null -ne $script:mountedISOPath -and $script:mountedISOPath -ne "") {
            try { Dismount-DiskImage -ImagePath $script:mountedISOPath -ErrorAction SilentlyContinue | Out-Null } catch {}
        }
        try { Remove-Item $script:sentinelFile -Force -ErrorAction SilentlyContinue } catch {}
        try { Remove-Item $script:stopFile     -Force -ErrorAction SilentlyContinue } catch {}
        $timerClock.Stop(); $timerSpinner.Stop()
        $toolTip.Dispose()
    })

# ============================================================
# FORM SHOWN
# ============================================================
$form.Add_Shown({
        Set-NavActive $btnNavAuto $btnNavIndiv $pageAuto $pageIndiv

        try {
            $os = Get-CimInstance Win32_OperatingSystem
            $uptime = (Get-Date) - $os.LastBootUpTime
            $lblSysInfo.Text = "$($os.Caption)  |  Build : $($os.BuildNumber)  |  Uptime : {0}j {1}h {2}m" -f [int]$uptime.TotalDays, $uptime.Hours, $uptime.Minutes
        }
        catch { $lblSysInfo.Text = "Informations systeme indisponibles" }

        Write-Log "======================================" "title"
        Write-Log "  WINMEDIC  v1.0.0" "title"
        Write-Log "  Assistant Reparation Windows" "title"
        Write-Log "  © ofbridge_lab" "title"
        Write-Log "======================================" "title"
        Write-Log ""
        Write-Log "Verification connexion Internet..." "info"
        Set-Status "Verification connexion..." "warn"

        $online = Test-Connection -ComputerName 8.8.8.8 -Count 1 -Quiet -ErrorAction SilentlyContinue
        if (-not $online) { $online = Test-Connection -ComputerName 1.1.1.1 -Count 1 -Quiet -ErrorAction SilentlyContinue }

        if ($online) {
            Write-Log "OK  Connexion Internet — Mode Online actif." "ok"
            $lblStatus.Text = "OK  Pret — Reparation via Windows Update disponible"
            $lblStatus.ForeColor = $clrGreen
            $btnAuto.BackColor = [System.Drawing.Color]::FromArgb(0, 50, 30)
            Set-Status "En ligne — Windows Update disponible" "ok"
        }
        else {
            Write-Log "WARN  Pas de connexion — Mode ISO requis." "warn"
            $lblStatus.Text = "WARN  Hors-ligne — Reparation via ISO requise"
            $lblStatus.ForeColor = $clrAmber
            $cbForceISO.Checked = $true
            $btnAuto.BackColor = [System.Drawing.Color]::FromArgb(50, 25, 0)
            Set-Status "Hors-ligne — ISO requis" "warn"
        }
        $btnAuto.Enabled = $true
    })

